        let high2 = theme.score_style(0.80);
        let med = theme.score_style(0.55);
        let med2 = theme.score_style(0.50);
        let low = theme.score_style(0.15);
        let low2 = theme.score_style(0.49);

        // Verify they're bold
        assert!(high.is_bold());
        assert!(med.is_bold());
        assert!(low.is_bold());
    }

